import{_ as t,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"78. Union Matters","description":"","frontmatter":{"title":"78. Union Matters","eba":"Biomedical Engineers 2025-2028","topics":["union-matters"]},"headers":[],"relativePath":"ebas/biomedical-engineers/union-matters/78-union-matters.md","filePath":"ebas/biomedical-engineers/union-matters/78-union-matters.md"}'),r={name:"ebas/biomedical-engineers/union-matters/78-union-matters.md"};function a(s,e,l,p,g,h){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_78-union-matters" tabindex="-1">78. Union Matters <a class="header-anchor" href="#_78-union-matters" aria-label="Permalink to &quot;78. Union Matters&quot;">​</a></h1><p><strong>78.1</strong> Access to Employees – General The Union will have access to Employees for any process arising under this Agreement.</p><p><strong>78.2</strong> Access to Employees – Electronic communication The Employer will ensure that:</p><p><strong>(a)</strong> emails from the Union domain name are not blocked or restricted by or on behalf of the Employer, except in respect of any individual Employee who has made a written request to the Employer to block such emails;</p><p><strong>(b)</strong> emails from Employees to the Union are not blocked or restricted by or on behalf of the Employer;</p><p><strong>(c)</strong> access from health service computers and like devices to Union websites and online information is not blocked, or limited; and</p><p><strong>(d)</strong> where a genuine security concern arises regarding the above, the Employer will immediately notify the Union to enable the security concern to be addressed.</p><p><strong>78.3</strong> Access to Employees – Orientation</p><p><strong>(a)</strong> The Union may attend and address new Employees as part of their orientation / induction, provided that any attendance for the purposes of discussions with the Employees meets the right of entry requirements under Part 3-4 of the Act (Entry Requirements).</p><p><strong>(b)</strong> Within 3 months of a new Employee/s commencement date, the details of such attendance will be arranged by the Employer in consultation with the Union, save that an Employer will advise the Union of the date, time and location of any general orientation / induction programs not less than 14 days prior to the orientation / induction program.</p><p><strong>(c)</strong> An Employer and Union may agree to an alternative means by which the Union can access new Employees (provided that such access is consistent with the Entry Requirements) including where:</p><p><strong>(i)</strong> orientation / induction programs are conducted on-line,</p><p><strong>(ii)</strong> the Union cannot reasonably attend, or</p><p><strong>(iii)</strong> the Employer provides new Employees with written information from the Union.</p><p><strong>78.4</strong> Delegates and HSRs NOTE: Additional rights of HSRs are contained in the OHS Act.</p><p><strong>(a)</strong> In this subclause 78.4:</p><p><strong>(i)</strong> Representative means a Union Delegate, or HSR;</p><p><strong>(ii)</strong> Relevant Employee means</p><p><strong>(A)</strong> In the case of a Union Delegate, members of the Union and any other persons eligible to be members of the Union; and <strong>(B)</strong> In the case of a HSR, members of the designated work group eligible to be represented by the HSR.</p><p><strong>(iii)</strong> Union Delegate means, for the purposes of this clause, an Employee who presents themselves as a delegate of a Union to their Employer, and is endorsed by the Union.</p><p><strong>(b)</strong> A Union Delegate is entitled to:</p><p><strong>(i)</strong> represent the industrial interests of Relevant Employees, including in disputes between that person and the Employer; and</p><p><strong>(ii)</strong> reasonable communication with members of the Union, and any other persons eligible to be members of the Union, in relation to their industrial interests.</p><p><strong>(c)</strong> For the purposes of representing the industrial interests of members of the Union and any other persons eligible to be members of the Union, a Union Delegate is entitled to reasonable access to the workplace of the Employer and any workplace facilities where work of the Employer is being undertaken.</p><p><strong>(d)</strong> A Representative is entitled to reasonable time release from duty to:</p><p><strong>(i)</strong> attend to matters relating to industrial, occupational health and safety or other relevant matters such as assisting with grievance procedures and attending committee meetings;</p><p><strong>(ii)</strong> access reasonable preparation time before meetings with management disciplinary or grievance meetings with a union member;</p><p><strong>(iii)</strong> in the case of a Union Delegate: <strong>(A)</strong> appear as a witness or participate in conciliation or arbitration, before the Commission; <strong>(B)</strong> present information on the Union at orientation sessions for new Employees.</p><p><strong>(e)</strong> A Representative required to attend management or consultative meetings outside of paid time will be paid to attend.</p><p><strong>(f)</strong> A Representative will be provided with access to facilities such as telephones, computers, email, noticeboards and meeting rooms in a manner that does not adversely affect service delivery and work requirements of the Employer. In the case of an HSR, facilities will include other facilities as necessary to enable them to perform their functions as prescribed under the OHS Act.</p><p><strong>(g)</strong> Except as otherwise required by law, the Employer will not:</p><p><strong>(i)</strong> unreasonably fail or refuse to deal with a Union Delegate; or</p><p><strong>(ii)</strong> knowingly or recklessly make a false or misleading representation to a Union Delegate; or</p><p><strong>(iii)</strong> unreasonably hinder, obstruct or prevent a Union Delegate from exercising any of their rights; insofar as the Union Delegate is acting in their capacity as a Representative.</p><p><strong>78.5</strong> Noticeboard</p><p><strong>(a)</strong> A noticeboard for the Union’s use will be readily accessible in each ward/unit/work area or nearest staff room where persons eligible to be members of the Union are employed.</p><p><strong>(b)</strong> The Union and members covered by this Agreement will, during the life of this Agreement, consult over the development of an electronic noticeboard managed by the Union.</p><p><strong>78.6</strong> Meeting Space In the absence of agreement on a location for the holding of Union meetings, the room where one or more of the Employees who may participate in the meeting ordinarily take meal or other breaks will be the meeting room for the purpose of Union meetings. Nothing in this clause is intended to override the operation of the Act.</p><p><strong>78.7</strong> Secondment to the Union The Employer will, on application, grant leave without pay to an Employee for the purpose of secondment or other arrangement to work for the Union subject to the Employer’s reasonable operational requirements.</p><p><strong>78.8</strong> Employees holding union official positions The Employer will, on application by the Union, grant leave without loss of pay to an Employee for the purpose of fulfilling their duties as an official of the Association or Executive body of the Union.</p><p><strong>78.9</strong> Union Training NOTE: Where a Union Delegate is also appointed as an HSR under the OHS Act, they may be entitled to additional training in accordance with the OHS Act.</p><p><strong>(a)</strong> Subject to the conditions in this subclause 78.9, Employees selected by the Union to attend training courses on industrial relations and/or health and safety will be entitled to a maximum of five days’ paid leave per calendar year per Employee.</p><p><strong>(b)</strong> Leave in excess of five days and up to ten days may be granted in a calendar year subject to the total leave being granted in that year and in the subsequent year not exceeding ten days.</p><p><strong>(c)</strong> The granting of leave will be subject to the Employer’s operational requirements. The granting of leave will not be unreasonably withheld.</p><p><strong>(d)</strong> Leave under this subclause is granted on the following conditions:</p><p><strong>(i)</strong> applications are accompanied by a statement from the Union advising that it has nominated the Employee or supports the application:</p><p><strong>(ii)</strong> the training is conducted by the Union, an association of unions or accredited training provider; and</p><p><strong>(iii)</strong> the application is made as early as practicable and not less than two (2) weeks before the training.</p><p><strong>(e)</strong> The Employee will be paid their ‘ordinary pay’ (as defined at 51 Annual Leave) for normal rostered hours (set out in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>), but excluding shift work, overtime and other allowances.</p><p><strong>(f)</strong> Leave in accordance with this clause may include necessary travelling time in normal hours immediately before or after the course.</p><p><strong>(g)</strong> Leave granted under this clause will count as service for all purposes of this Agreement.</p><p><strong>(h)</strong> Expenses associated with attendance at training courses, including fares, accommodation and meal costs are not the responsibility of the Employer.</p><p><strong>78.10</strong> Workplace Implementation Committees</p><p><strong>(a)</strong> A local Workplace Implementation Committee (WIC) will continue or, if there is not currently a WIC in operation, be established at each Employer. Having regard for the size and location, a WIC may be appropriate at each facility/campus. The WIC will, where practicable, comprise equal numbers of representatives of the Employer and the Union for the purposes of:</p><p><strong>(i)</strong> agreement implementation;</p><p><strong>(ii)</strong> on-going monitoring and assessment of the implementation of this Agreement; and</p><p><strong>(iii)</strong> to deal with any local disputes that may arise, without limiting the Dispute Resolution Procedure in this Agreement.</p><p><strong>(b)</strong> Priority items for consideration by the WIC will include the matters arising under <a href="/eba/ebas/biomedical-engineers/leave/56-family-violence-leave.html">clause 56</a> (Family Violence) and this clause 78 (Union Matters).</p><p>Plain language terms: union rep, delegate.</p>',59)])])}const d=t(r,[["render",a]]);export{m as __pageData,d as default};
